import ldap3

def search_user_by_username(ldap_server, ldap_port, base_dn, username):
    try:
        server = ldap3.Server(ldap_server, port=ldap_port, get_info=ldap3.ALL)
        connection = ldap3.Connection(server, auto_bind=True)

        search_filter = f"(uid={username})"
        attributes = ['cn', 'mail', 'telephoneNumber']

        connection.search(base_dn, search_filter, attributes=attributes)

        if connection.entries:
            user_info = {
                'common_name': connection.entries[0].cn.value,
                'email': connection.entries[0].mail.value,
                'phone_number': connection.entries[0].telephoneNumber.value
            }
            return user_info
        else:
            return None

    except ldap3.core.exceptions.LDAPException as e:
        print(f"LDAP error: {e}")
        return None

    finally:
        if connection.bound:
            connection.unbind()